INSERT INTO "contact_submissions" ("id", "name", "email", "phone", "course_interest", "message", "created_at") VALUES ('833ccdea-22e7-4ee6-b1f8-f76ddae9bdb8', 'Marco Rossi', 'marco.rossi@gmail.com', '+39 348 1234567', 'Inglese B2 - Corso di Gruppo', 'Buongiorno, vorrei informazioni sui corsi di inglese livello B2 in presenza a Vicenza. Lavoro in un''azienda manifatturiera e ho bisogno di migliorare il mio inglese per le riunioni con clienti internazionali. Quali sono gli orari disponibili?', '2026-03-05T19:54:47.056Z') ON CONFLICT DO NOTHING;
INSERT INTO "contact_submissions" ("id", "name", "email", "phone", "course_interest", "message", "created_at") VALUES ('8b96fcb0-4539-4b21-96bf-7b9dc58594a0', 'Elena Colombo', 'elena.colombo@libero.it', '+39 333 9876543', 'Tedesco A1 - Corso Individuale', 'Salve, il mio compagno è tedesco e vorrei iniziare a studiare la lingua da zero. Preferisco lezioni individuali. Quanto costa un pacchetto di 10 lezioni?', '2026-03-05T19:54:49.063Z') ON CONFLICT DO NOTHING;
INSERT INTO "contact_submissions" ("id", "name", "email", "phone", "course_interest", "message", "created_at") VALUES ('3f3fd669-25a4-4507-9352-e442bb2b9f26', 'Francesco Conti', 'f.conti@aziendavicenza.it', '+39 0444 567890', 'Full Immersion English', 'Sono il responsabile HR di un''azienda con 50 dipendenti. Vorremmo organizzare un corso Full Immersion di una settimana per 8 manager. È possibile farlo nella nostra sede? Grazie.', '2026-03-05T19:54:50.121Z') ON CONFLICT DO NOTHING;
INSERT INTO "contact_submissions" ("id", "name", "email", "phone", "course_interest", "message", "created_at") VALUES ('5e289c93-90e4-4b55-9613-08b9b72f1b73', 'Sofia Ricci', 'sofia.ricci@hotmail.com', '+39 345 2345678', 'Francese B1 - E-Learning', 'Ciao, mi interessa il corso di francese online. Posso iniziare in qualsiasi momento o ci sono date fisse? Ho già un livello A2 certificato.', '2026-03-05T19:54:50.979Z') ON CONFLICT DO NOTHING;
INSERT INTO "contact_submissions" ("id", "name", "email", "phone", "course_interest", "message", "created_at") VALUES ('7e431295-5b85-43f3-8c5e-dc36a787b3f9', 'Luca Moretti', 'luca.moretti@gmail.com', '+39 347 3456789', 'Language Coaching - Inglese', 'Ho bisogno di prepararmi per una presentazione in inglese davanti a 200 persone tra 3 settimane. Cerco un coach che mi aiuti con la pronuncia e la sicurezza nel parlare. Budget non è un problema.', '2026-03-05T19:54:51.672Z') ON CONFLICT DO NOTHING;
