INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1609, 'A0', 'reading', 'reading', 'travel', 'A che ora parte il treno?', '["Alle 9:30","Alle 10:00","Alle 8:15","Alle 12:00"]', 'Alle 9:30', NULL, 'Avviso: Il treno per Roma parte alle ore 9:30 dal binario 3.', NULL, -279, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1610, 'A1', 'reading', 'reading', 'everyday_life', 'Dove abita Marco?', '["A Firenze","A Roma","A Milano","A Napoli"]', 'A Firenze', NULL, 'Mi chiamo Marco e abito a Firenze. Ho 25 anni e lavoro in un ufficio. La sera mi piace leggere e guardare la televisione.', NULL, -190, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1611, 'A1', 'reading', 'reading', 'food', 'Cosa compra Giulia al mercato?', '["Frutta e verdura","Vestiti","Libri","Scarpe"]', 'Frutta e verdura', NULL, 'Giulia va al mercato ogni sabato mattina. Compra frutta e verdura fresca per la settimana. Le piacciono molto le fragole e i pomodori.', NULL, -184, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1612, 'A1', 'reading', 'reading', 'travel', 'Come va Maria al lavoro?', '["In autobus","In macchina","A piedi","In bicicletta"]', 'In autobus', NULL, 'Maria prende l''autobus ogni mattina per andare al lavoro. La fermata è vicino a casa sua. Il viaggio dura circa venti minuti.', NULL, -179, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1613, 'A2', 'reading', 'reading', 'culture', 'Perché Venezia è famosa?', '["Per i suoi canali e gondole","Per le montagne","Per le spiagge","Per i vulcani"]', 'Per i suoi canali e gondole', NULL, 'Venezia è una delle città più belle d''Italia. È famosa in tutto il mondo per i suoi canali e le sue gondole. Ogni anno milioni di turisti visitano la città per ammirare la sua architettura unica e partecipare al famoso Carnevale.', NULL, -90, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1614, 'A2', 'reading', 'reading', 'work', 'Quali requisiti servono per il lavoro?', '["Laurea ed esperienza","Solo il diploma","Nessun requisito","Solo la patente"]', 'Laurea ed esperienza', NULL, 'Cercasi impiegato per ufficio commerciale. Requisiti: laurea in economia, esperienza di almeno due anni nel settore vendite, buona conoscenza dell''inglese. Orario: lunedì-venerdì, 9:00-18:00. Inviare CV a info@azienda.it.', NULL, -84, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1615, 'B1', 'reading', 'reading', 'culture', 'Qual è l''argomento principale del testo?', '["L''importanza della dieta mediterranea","La storia della pizza","I ristoranti italiani","Le ricette tradizionali"]', 'L''importanza della dieta mediterranea', NULL, 'La dieta mediterranea è stata riconosciuta dall''UNESCO come patrimonio immateriale dell''umanità nel 2010. Questo modello alimentare, basato sul consumo di olio d''oliva, cereali, frutta, verdura e pesce, è associato a numerosi benefici per la salute, tra cui la riduzione del rischio di malattie cardiovascolari.', NULL, 10, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1616, 'B1', 'reading', 'reading', 'work', 'Cosa critica l''autore?', '["L''eccessivo uso della tecnologia al lavoro","I bassi stipendi","Le ferie troppo brevi","L''orario di lavoro"]', 'L''eccessivo uso della tecnologia al lavoro', NULL, 'Nell''era digitale, molti lavoratori si trovano costantemente connessi. Le email, le videochiamate e le notifiche continue rendono difficile separare il tempo lavorativo da quello personale. Diversi esperti sostengono che questa iperconnessione riduca la produttività e aumenti lo stress, creando un paradosso tecnologico.', NULL, 16, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1617, 'B2', 'reading', 'reading', 'culture', 'Qual è la tesi dell''autore?', '["Che il turismo di massa danneggia le città d''arte","Che il turismo è sempre positivo","Che le città italiane sono poco visitate","Che i musei dovrebbero chiudere"]', 'Che il turismo di massa danneggia le città d''arte', NULL, 'Il turismo di massa rappresenta una delle sfide più significative per le città d''arte italiane. Se da un lato porta evidenti benefici economici, dall''altro contribuisce al degrado del patrimonio storico, all''aumento del costo della vita per i residenti e alla perdita dell''identità culturale dei centri storici. Firenze, Venezia e Roma sono tra le città più colpite da questo fenomeno, con un numero annuo di visitatori che supera di gran lunga la capacità sostenibile.', NULL, 110, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1618, 'B2', 'reading', 'reading', 'everyday_life', 'Cosa suggerisce l''articolo?', '["Un approccio equilibrato all''uso dei social media","Eliminare tutti i social media","Usare i social media il più possibile","Che i social media non hanno effetti"]', 'Un approccio equilibrato all''uso dei social media', NULL, 'I social media hanno rivoluzionato il modo in cui comunichiamo, ma emergono crescenti preoccupazioni riguardo al loro impatto sulla salute mentale. Studi recenti dimostrano una correlazione tra l''uso eccessivo dei social e disturbi d''ansia, depressione e problemi di autostima, soprattutto tra i giovani. Tuttavia, gli esperti sottolineano che non si tratta di demonizzare questi strumenti, bensì di promuovere un utilizzo consapevole e bilanciato.', NULL, 116, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1619, 'C1', 'reading', 'reading', 'culture', 'Qual è il paradosso descritto dall''autore?', '["Che la globalizzazione omologa le culture mentre promette diversità","Che la tecnologia è troppo costosa","Che l''Italia non ha cultura","Che le tradizioni sono inutili"]', 'Che la globalizzazione omologa le culture mentre promette diversità', NULL, 'La globalizzazione culturale presenta un paradosso fondamentale: mentre promette di avvicinare i popoli e favorire lo scambio interculturale, tende in realtà a omologare le espressioni culturali locali, sostituendole con modelli standardizzati di origine prevalentemente anglosassone. L''Italia, con il suo ricchissimo patrimonio di dialetti, tradizioni culinarie regionali e pratiche artigianali, si trova a dover bilanciare l''apertura verso l''esterno con la preservazione di un''identità culturale millenaria.', NULL, 210, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
INSERT INTO "be_questions" ("id", "level", "skill_type", "section", "topic", "question", "options", "correct_answer", "audio_url", "passage", "explanation", "difficulty", "discrimination", "calibration_status", "calibration_notes", "language") VALUES (1620, 'C1', 'reading', 'reading', 'work', 'Qual è la conclusione dell''autore?', '["Che servono nuove politiche per gestire la transizione digitale del lavoro","Che il lavoro da remoto è impossibile","Che le aziende non devono cambiare","Che la tecnologia non influenza il lavoro"]', 'Che servono nuove politiche per gestire la transizione digitale del lavoro', NULL, 'La trasformazione digitale del mercato del lavoro italiano solleva interrogativi complessi sul futuro dell''occupazione. L''automazione e l''intelligenza artificiale stanno ridefinendo interi settori produttivi, rendendo obsolete alcune competenze e creandone di nuove. Il sistema formativo italiano, ancora largamente ancorato a modelli novecenteschi, fatica ad adeguarsi alla velocità del cambiamento. È necessario un ripensamento radicale delle politiche del lavoro e della formazione per garantire una transizione equa e inclusiva.', NULL, 216, 100, 'calibrated', NULL, 'italian') ON CONFLICT DO NOTHING;
