INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (1, 17, 'writing', 'Write a well-structured opinion essay on whether governments should invest more in renewable energy. Support your argument with examples.', 'The listening comprehension section now uses real audio files. I generated 90 MP3 files using 6 different TTS voices for accent variety, with a play/pause button and a 2-play limit per question. When you reach the listening section during a test, does the audio player work well for you?', NULL, 'A0', 10, 10, 5, 0, 'The response does not address the prompt about renewable energy and instead discusses an unrelated topic about listening comprehension. Please ensure your response is relevant to the task and provides a clear opinion on the investment in renewable energy, supported by examples. Focus on organizing your essay with an introduction, body paragraphs, and a conclusion.', '2026-03-01T11:20:44.417Z') ON CONFLICT DO NOTHING;
INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (2, 18, 'writing', 'Write a well-structured opinion essay on whether governments should invest more in renewable energy. Support your argument with examples.', '**Should Governments Invest More in Renewable Energy?**
INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (3, 20, 'writing', 'Write 3-4 simple sentences about yourself: your name, where you live, and one thing you like.', 'jhvb kuhiuk  kujghiu ; k.jhiluk frfr  efefg ', NULL, 'A0', 0, 0, 0, 0, 'The response does not contain any recognizable English words or sentences. To improve, focus on writing simple sentences using basic vocabulary, such as ''My name is...'', ''I live in...'', and ''I like...''. Practice forming complete sentences to convey clear information.', '2026-03-01T11:58:10.697Z') ON CONFLICT DO NOTHING;
INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (4, 20, 'speaking', 'Tell me your name and where you are from. Use very simple words.', 'hello hello hello hello hello hello', NULL, 'A0', 5, 5, 5, 5, 'The response does not address the prompt as it only repeats the word ''hello'' multiple times. To improve, try to include your name and where you are from using simple sentences. Practice forming basic sentences to better communicate your ideas.', '2026-03-01T11:58:25.150Z') ON CONFLICT DO NOTHING;
INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (5, 21, 'writing', 'Write 3-4 simple sentences about yourself: your name, where you live, and one thing you like.', 'hello I am me ', NULL, 'A0', 10, 10, 5, 5, 'The response is very minimal and does not fully address the prompt. Try to include more information, such as your name, where you live, and something you like. Practice forming complete sentences with proper capitalization and punctuation.', '2026-03-01T12:03:16.531Z') ON CONFLICT DO NOTHING;
INSERT INTO "be_writing_speaking" ("id", "session_id", "task_type", "prompt", "response", "audio_url", "ai_score", "ai_grammar_score", "ai_vocabulary_score", "ai_coherence_score", "ai_task_completion_score", "ai_feedback", "submitted_at") VALUES (6, 21, 'speaking', 'Tell me your name and where you are from. Use very simple words.', 'Hello, hello, hello, hello, hello, hello.', NULL, 'A0', 10, 10, 5, 0, 'The response did not address the prompt as it only repeated the word ''hello'' multiple times. Try to provide your name and where you are from using simple sentences. Practicing basic introductions will help improve your language skills.', '2026-03-01T12:03:29.185Z') ON CONFLICT DO NOTHING;
