INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('97f15a7d-fcfd-4c9a-83d8-8f513485bc3a', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Luca B.', 'Non ho mai pensato alla formazione continua come un investimento... ma dopo aver letto questo articolo, credo sia davvero essenziale per rimanere competitivi.', false, NULL, true, '2026-03-01T23:19:58.849Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('ca781dfc-2906-4c86-aa47-785c3031a3cb', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Il Team di Interlingua', 'È interessante come la percezione della formazione continua possa cambiare con nuove informazioni. Investire nelle proprie competenze non solo apre a nuove opportunità, ma aiuta anche a rimanere al passo con le evoluzioni del mercato. Se ti va, potresti approfondire alcuni corsi che potrebbero fare al caso tuo.', true, '97f15a7d-fcfd-4c9a-83d8-8f513485bc3a', true, '2026-03-01T23:20:00.275Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('41a106cb-e152-49cc-bc4a-5d0b54b9e659', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Martina S.', 'Ho iniziato a seguire un corso di aggiornamento l''anno scorso e ho notato un miglioramento incredibile nel mio lavoro. È vero che rimanere al passo è fondamentale, soprattutto in un settore in rapida evoluzione come il nostro.', false, NULL, true, '2026-03-01T23:20:00.279Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('0ffcb86e-3d2a-4b7b-b8dc-ce8b415dd939', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Il Team di Interlingua', 'È davvero incoraggiante sentire che il tuo corso di aggiornamento ha portato a risultati così positivi! In un settore in continua evoluzione, investire nella propria formazione è senza dubbio un passo cruciale. Se hai bisogno di ulteriori suggerimenti o corsi per continuare a crescere, siamo qui per aiutarti.', true, '41a106cb-e152-49cc-bc4a-5d0b54b9e659', true, '2026-03-01T23:20:01.935Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('6631eb1f-1a43-4434-bb84-47d1c30eac42', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Giovanni P.', 'Mmm... sono un po'' scettico riguardo ai corsi online. A volte sembra più una moda che una reale necessità. Magari dipende dal campo, ma non sono sicuro che facciano davvero la differenza.', false, NULL, true, '2026-03-01T23:20:01.939Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('fade4a15-a790-4c05-a5f3-22b6fd4ea03b', '2026-03-01-formazione-professionale-continua-investire-nel-futuro-per-rimanere-competitivi', 'Il Team di Interlingua', 'Capisco il tuo scetticismo, Giovanni. È vero che l''offerta di corsi online può sembrare eccessiva e talvolta superficiale. Tuttavia, molti di questi corsi sono progettati con un focus pratico e possono davvero apportare valore, specialmente in settori in continua evoluzione. La chiave è scegliere programmi di qualità, che siano riconosciuti e pertinenti al tuo campo. Se hai domande specifiche su corsi, sono qui per aiutarti!', true, '6631eb1f-1a43-4434-bb84-47d1c30eac42', true, '2026-03-01T23:20:04.142Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('2588ce83-875f-4c34-be0e-280516d8286b', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Luca M.', 'Excel avanzato? Ho sempre pensato fosse solo per i geni! Ma mi sa che devo rimettermi in pista... quali sono le funzioni chiave che devo assolutamente imparare?', false, NULL, true, '2026-03-01T23:20:06.843Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('ae068254-6276-4c4d-83c2-41aab06911b7', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Il Team di Interlingua', 'È comprensibile pensare che Excel avanzato sia per pochi, ma in realtà è alla portata di tutti con un po'' di impegno. Tra le funzioni chiave da apprendere, ti consiglio di focalizzarti su formule come VLOOKUP, INDEX e MATCH, oltre a strumenti come le tabelle pivot e i grafici avanzati. Se hai bisogno di un supporto più strutturato, i nostri corsi possono aiutarti a diventare esperto in poco tempo.', true, '2588ce83-875f-4c34-be0e-280516d8286b', true, '2026-03-01T23:20:08.799Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('cb45de6b-7e8b-4325-a224-42dae2aeedec', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Sara P.', 'Ho seguito un corso di Excel avanzato e ho iniziato a usare le tabelle pivot e i grafici dinamici... è una roba incredibile! Non riesco a credere come possa semplificare il lavoro. Consiglio a chiunque di provarci!', false, NULL, true, '2026-03-01T23:20:08.802Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('fca43b1e-d387-403e-b393-ef8507c87da5', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Il Team di Interlingua', 'È davvero interessante sentire come l''uso delle tabelle pivot e dei grafici dinamici abbia semplificato il tuo lavoro. Excel offre strumenti potenti per trasformare i dati in informazioni utili. Hai già provato a integrare queste competenze in progetti specifici?', true, 'cb45de6b-7e8b-4325-a224-42dae2aeedec', true, '2026-03-01T23:20:09.959Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('7e79f7b6-a73e-4858-a151-c852a91f446c', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Marco Z.', 'Miga facile come sembra. Ho provato a fare qualche analisi con le formule complesse e mi sono perso. Secondo me ci vuole un sacco di pratica. Chi ha qualche trucco da suggerire?', false, NULL, true, '2026-03-01T23:20:09.962Z') ON CONFLICT DO NOTHING;
INSERT INTO "blog_comments" ("id", "blog_slug", "author_name", "content", "is_ai_reply", "parent_id", "approved", "created_at") VALUES ('53ec5f94-91e0-4fe2-abcd-e9499ccbf2e7', '2026-02-28-domina-excel-avanzato-trasforma-i-dati-in-decisioni-strategic', 'Il Team di Interlingua', 'Hai ragione, Marco. Excel può sembrare ostico con le formule complesse, ma la pratica è fondamentale per acquisire sicurezza. Un consiglio utile è iniziare con funzioni più semplici e, man mano, affrontare quelle avanzate, magari creando un piccolo progetto personale. Se hai bisogno di supporto, il nostro corso di Excel Avanzato offre strategie pratiche proprio per questo!', true, '7e79f7b6-a73e-4858-a151-c852a91f446c', true, '2026-03-01T23:20:11.540Z') ON CONFLICT DO NOTHING;
