INSERT INTO "product_reviews" ("id", "product_slug", "author_name", "author_email", "rating", "title", "comment", "verified", "approved", "created_at") VALUES ('b8c03d52-75d2-4201-8902-85a02e38021b', 'italiano-individuale-presenza', 'Anna S.', 'anna.s@example.com', 5, 'Personalizzazione perfetta', 'Le lezioni individuali mi hanno permesso di concentrarmi esattamente su ciò di cui avevo bisogno per il mio lavoro. L''insegnante ha adattato tutto al mio ritmo.', true, true, '2026-03-05T23:45:54.521Z') ON CONFLICT DO NOTHING;
INSERT INTO "product_reviews" ("id", "product_slug", "author_name", "author_email", "rating", "title", "comment", "verified", "approved", "created_at") VALUES ('23a1a17e-d3f6-4caa-ad3b-e21bfeef86c0', 'full-immersion', 'Marco B.', 'marco.b@example.com', 5, 'Esperienza trasformativa', 'Una settimana di Full Immersion che ha cambiato il mio livello di inglese. L''ambiente stimolante e i docenti preparati fanno davvero la differenza. Consigliato a chi vuole fare un salto di qualità.', true, true, '2026-03-05T23:45:14.862Z') ON CONFLICT DO NOTHING;
INSERT INTO "product_reviews" ("id", "product_slug", "author_name", "author_email", "rating", "title", "comment", "verified", "approved", "created_at") VALUES ('9871ba15-56e5-425d-b197-e23c7f1a6449', 'italiano-individuale-online', 'David H.', 'david.h@example.com', 5, 'Excellent online lessons', 'I was skeptical about online Italian lessons but the quality is outstanding. My teacher is wonderful and the flexibility of scheduling from home is a huge plus.', true, true, '2026-03-05T23:45:58.268Z') ON CONFLICT DO NOTHING;
INSERT INTO "product_reviews" ("id", "product_slug", "author_name", "author_email", "rating", "title", "comment", "verified", "approved", "created_at") VALUES ('b14d05d4-0478-4d6a-9e8b-67e9bb0fb7a9', 'full-immersion', 'Elena R.', 'elena.r@example.com', 5, 'Intensivo ma efficace', 'Ho scelto il formato weekend e sono rimasta sorpresa dai risultati. In sole due giornate intensive ho superato molte delle mie barriere nel parlare inglese.', true, true, '2026-03-05T23:45:19.191Z') ON CONFLICT DO NOTHING;
INSERT INTO "product_reviews" ("id", "product_slug", "author_name", "author_email", "rating", "title", "comment", "verified", "approved", "created_at") VALUES ('f70352a0-f73d-4c3b-821f-20d94f2eefac', 'full-immersion', 'Giovanni P.', 'giovanni.p@example.com', 4, 'Ottimo investimento', 'La settimana Full Immersion è stata impegnativa ma estremamente produttiva. Ho migliorato soprattutto la fluency e la comprensione. Docenti eccellenti.', true, true, '2026-03-05T23:45:23.252Z') ON CONFLICT DO NOTHING;
